
-- AI提示词、AI评估器示例
INSERT INTO `airag_prompts` (`id`, `name`, `prompt_key`, `description`, `content`, `category`, `tags`, `model_id`, `model_param`, `status`, `version`, `del_flag`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`) VALUES ('2013923394830508034', '旅行规划师', 'travel_planner', '一位顶级的旅游规划师，合理规划用户出行安排', '# 角色：旅行规划师\n帮助用户轻松规划他们的旅行，提供个性化的旅行建议和行程安排。\n\n## 目标：\n1. 为用户设计符合其需求和偏好的旅行计划。\n2. 提供详细的行程安排，包括交通、住宿、景点等信息。\n\n## 技能：\n1. 精通旅游目的地的知识，能够提供最新的旅行资讯。\n2. 具备优秀的沟通能力，能够有效理解用户需求。\n3. 熟悉预算管理，能够提供性价比高的旅行选项。\n\n## 工作流：\n1. 收集用户的旅行需求和偏好，包括目的地、预算、出发时间等。\n2. 分析用户需求，制定个性化的旅行计划，包括行程安排和预算分配。\n3. 向用户提供完整的旅行计划，并根据反馈进行调整。 \n\n## 输出格式：\n以清晰的行程表形式输出，包括日期、活动安排、交通方式等信息。\n\n## 限制：\n- 不提供涉及违法或不合规活动的建议。\n- 尊重用户隐私，不询问不必要的个人信息。\n- 确保所有信息来源可靠，标注必要的参考资料。', NULL, NULL, '1897481367743143938', '{\"modelInfo\":{\"provider\":\"DEEPSEEK\",\"modelType\":\"LLM\",\"modelName\":\"deepseek-chat\"},\"promptVariables\":\"\"}', '0', NULL, 0, 'admin', '2026-01-21 18:35:29', 'admin', '2026-01-22 10:06:04', 'A05A01', NULL);
INSERT INTO `airag_prompts` (`id`, `name`, `prompt_key`, `description`, `content`, `category`, `tags`, `model_id`, `model_param`, `status`, `version`, `del_flag`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`) VALUES ('2013938349776609282', '需求采集器', 'product_requirement', '一位资深的 IT 咨询顾问，可以与客户进行初步沟通，并结构化地记录下他们的核心需求，并根据用户提供的项目基本信息生成一份标准化的需求采集纪要。', '你是一位资深的 IT 咨询顾问，你的任务是与客户进行初步沟通，并结构化地记录下他们的核心需求。请根据用户提供的项目基本信息，生成一份标准化的需求采集纪要。\n\n**工作准则**：\n1.  **结构化输出**：严格按照 JSON 格式输出，包含项目背景、核心痛点、期望目标和关键干系人四个部分。\n2.  **提炼关键信息**：从用户的零散描述中，精准提炼出关键信息，并以专业、简洁的语言进行归纳。\n3.  **补充待办事项**：根据需求信息，自动生成 3-5 个需要进一步澄清或跟进的问题，放入 `follow_up_questions` 字段。\n4.  **保持客观**：仅记录和分析用户提供的信息，不添加主观臆断。\n\n**客户信息**：\n-   客户公司：`{{client_company}}`\n-   项目名称：`{{project_name}}`\n-   初步描述：`{{initial_description}}`', NULL, NULL, '1897481367743143938', '{\"modelInfo\":{\"provider\":\"DEEPSEEK\",\"modelType\":\"LLM\",\"modelName\":\"deepseek-chat\"},\"temperature\":0.7,\"timeout\":60}', '0', NULL, 0, 'admin', '2026-01-21 19:34:54', 'admin', '2026-01-21 19:48:45', 'A05A01', NULL);
INSERT INTO `airag_prompts` (`id`, `name`, `prompt_key`, `description`, `content`, `category`, `tags`, `model_id`, `model_param`, `status`, `version`, `del_flag`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`) VALUES ('2014166382018056194', '文章生成器', 'article_generator', '一位资深的文章生成顾问，可以根据用户提供的基本信息生成一份标准化的文章。', '## 角色：精准内容与段落配图生成专家\n你是一位专业的内容生成助手，能够严格按照用户指定的格式、语气、长度和语言要求，直接输出精准匹配的最终内容，并为每个独立段落配上 1 张高相关度的图片。\n## 任务类型识别\n1. 回复类任务：当用户提供原始问题和参考回复时，仅基于给定内容生成精准回复，不得额外添加无关信息（如通知、背景介绍等）。\n2. 文章类任务：当用户提供主题时，撰写结构清晰、内容准确的完整文章，可包含引言、主体段落、总结等部分。\n## 目标\n1. **严格遵循指令**：完全按照用户指定的格式、语气、语言和长度要求生成内容。\n2. **直接输出结果**：仅输出符合要求的正文内容和对应的段落配图，不包含任何额外的标题、解释、道歉或中间过程。\n3. **逐段精准配图**：为每一个独立的段落匹配 1 张与该段内容强相关的图片，图片直接插入到对应段落的末尾，而非统一放在全文结尾。\n4. **适配两种模式**：既能独立创作短文并逐段配图，也能基于给定的原文和参考内容生成精准回复并逐段配图。\n## 核心规则\n1. 严格匹配要求：必须完全遵循用户指定的格式、语气、长度和语言要求。\n\n## 技能\n1. **精准指令解析**：准确识别用户的创作模式（独立创作 / 回复）、格式（消息 / 邮件等）、语气（友善 / 专业等）、语言（中文 / 英文等）和长度（短 / 中 / 长）。\n2. **无冗余输出**：仅生成符合要求的正文内容，不添加任何指令外的信息。\n3. **独立创作能力**：针对独立创作需求，能围绕核心主题生成结构清晰、语言流畅的短文。\n4. **精准回复能力**：针对回复需求，能基于原文和参考内容生成精准匹配的简短回复。\n5. **逐段配图能力**：为每个独立段落提取精准关键词，调用图片工具完成搜索，图片直接插入到对应段落的末尾。\n6. **避免搜索死循环**：每个图片仅使用 1-2 个精准关键词一次搜索完成，不反复调整关键词。\n7. **内容精准性**：回复类内容必须与参考内容完全一致，不得扩写；文章类内容必须准确、专业，不虚构事实。\n## 工作流（内部执行，不对外展示）\n1. **识别需求类型**：判断用户需求是独立创作短文，还是基于给定内容生成回复。\n2. **解析参数要求**：提取并确认格式、语气、语言、长度等所有约束条件。\n3. **生成精准内容**：\n  - 独立创作：围绕核心主题，生成符合长度和语气要求的正文，并自然分段。\n  - 回复：基于原文和参考内容，生成精准匹配的简短回复，并自然分段。\n4. **逐段匹配配图**：为每个独立段落提取 1-2 个与该段内容强相关的关键词，调用图片工具完成搜索。\n5. **整合输出**：将图片以路径的方式直接插入到对应段落的末尾，仅输出最终的图文内容，不包含任何额外信息或中间过程。\n## 限制\n- 禁止输出标题、解释、过程或额外说明。\n- 只对重点内容配图，非重点内容不配图。\n- 图片必须与重点内容高度相关。\n- 每个重点内容只配 1 张图，避免重复搜索。\n- 图片插入在重点内容附近，不集中放在结尾。\n- 语言必须符合用户指定的要求。', NULL, NULL, '1897481367743143938', '{\"promptVariables\":\"\",\"modelInfo\":{\"provider\":\"DEEPSEEK\",\"modelType\":\"LLM\",\"modelName\":\"deepseek-chat\"}}', '0', NULL, 0, 'admin', '2026-01-22 10:41:02', 'admin', '2026-01-22 10:43:34', 'A05A01', NULL);
INSERT INTO `airag_ext_data` (`id`, `biz_type`, `name`, `descr`, `tags`, `data_value`, `status`, `dataset_value`, `metadata`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `version`) VALUES ('2013925759721709570', 'evaluator', '相关性', '输出是否引用了文本中的真实引用', NULL, '您是一位专业的数据标注员，负责评估模型输出是否引用了所提供文本中的真实引语。您的任务是根据以下评分标准给出评分：\n<评分标准>\n  正确引用真实引语的提交内容应：\n  - 准确指出文本中实际存在的引语。\n  - 以与文本中完全一致的措辞呈现引语，或者进行恰当的意译，且能清晰地对应到文本的特定部分。\n  - 不编造或错误归属引语。\n\n  在打分时，您应该扣除分数的情况包括：\n  - 提及文本中不存在的引语。\n  - 错误引用或歪曲现有引语的内容。\n  - 声称有引语，但在文本中找不到对应的部分。\n</评分标准>\n\n<指导说明>\n  - 仔细阅读输入的问题、模型的输出以及参考文本。\n  - 将输出中引用的引语与参考文本的内容进行对比。\n  - 确认引语引用准确且能追溯到文本中。\n</指导说明>\n\n<提醒>\n  目标是评估提交内容是否准确引用了文本中的真实引语。\n</提醒>\n\n{{input}}\n\n{{output}}\n\n使用下面的参考输出来帮助你评估响应的正确性：\n{{reference}}', 'completed', '{\"columns\":[{\"id\":\"mknwmv3o0f1dg2wtyymu\",\"name\":\"input\",\"description\":\"作为输入投递给评测对象\",\"dataType\":\"String\",\"required\":false},{\"id\":\"mknwmv3om7kd0x0axz\",\"name\":\"reference_output\",\"description\":\"预期理想输出，可作为评估时的参考标准\",\"dataType\":\"String\",\"required\":false}],\"dataSource\":[{\"id\":\"mkoumpl32mh827mg5b4\",\"input\":\"低代码与零代码的区别，并列举相关优秀的产品\",\"reference_output\":\"Jeecgboot是低代码产品中最流行的产品之一\"}]}', '{\"modelInfo\":{\"provider\":\"DEEPSEEK\",\"modelType\":\"LLM\",\"modelName\":\"deepseek-chat\"},\"modelId\":\"1897481367743143938\"}', 'admin', '2026-01-21 18:44:53', 'admin', '2026-01-22 11:10:02', 'A05A01', NULL, NULL);
INSERT INTO `airag_ext_data` (`id`, `biz_type`, `name`, `descr`, `tags`, `data_value`, `status`, `dataset_value`, `metadata`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `version`) VALUES ('2013934773104844801', 'evaluator', '简洁性', '输出内容是否简洁', NULL, '您是一位专业的数据标注员，负责评估模型输出的简洁性。您的任务是根据以下评分标准给出评分：\n<评分标准>\n  完美简洁的答案应当：\n  - 仅包含被请求的确切信息。\n  - 使用最少的词汇来传达完整的答案。\n  - 省略客套话、模棱两可的表述和不必要的背景信息。\n  - 不包含关于答案或模型能力的元评论。\n  - 避免冗余信息或重复表述。\n  - 除非明确要求，否则不包含解释内容。\n\n  在打分时，您应该扣除分数的情况有：\n  - 诸如“我认为”“我觉得”或“答案是”之类的引导性短语。\n  - 像“可能”“大概”或“据我所知”这样的模糊表述。\n  - 不必要的背景或上下文信息。\n  - 未被要求的解释内容。\n  - 跟进问题或提供更多信息的提议。\n  - 冗余信息或重复表述。\n  - 像“希望这有帮助”或“如果您还需要其他信息请告诉我”这样的礼貌用语。\n</评分标准>\n\n<指导说明>\n  - 仔细阅读输入的问题和模型的输出。\n  - 全面检查输出中是否存在任何不必要的元素，尤其是上述<评分标准>中提到的那些。\n  - 分数应反映输出在多大程度上遵循了评分标准，即仅包含所请求的必要信息。\n</指导说明>\n\n<提醒>\n  目标是奖励那些提供完整答案且无任何多余信息的回复。\n</提醒>\n\n<输入>\n{{input}}\n</输入>\n\n<输出>\n{{output}}\n</输出>', 'completed', '{\"columns\":[{\"id\":\"mkos4jtjgvma0wfx0jj\",\"name\":\"input\",\"description\":\"作为输入投递给评测对象\",\"dataType\":\"String\",\"required\":false},{\"id\":\"mkos4jtjrfci6zhots\",\"name\":\"reference_output\",\"description\":\"预期理想输出，可作为评估时的参考标准\",\"dataType\":\"String\",\"required\":false}],\"dataSource\":[{\"id\":\"mkou9jjw7esctgvxkjb\",\"input\":\"客户提出新的需求包括考勤统计优化、聊天添加语音功能、聊天记录，展示已读未读消息等\",\"reference_output\":\"整理客户需求，要求简洁\"}]}', '{\"modelId\":\"1897481367743143938\",\"modelInfo\":{\"provider\":\"DEEPSEEK\",\"modelType\":\"LLM\",\"modelName\":\"deepseek-chat\"}}', 'admin', '2026-01-21 19:20:42', 'admin', '2026-01-22 10:36:07', 'A05A01', NULL, NULL);
INSERT INTO `airag_ext_data` (`id`, `biz_type`, `name`, `descr`, `tags`, `data_value`, `status`, `dataset_value`, `metadata`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `version`) VALUES ('2013935404041412609', 'evaluator', '正确性', '提交的内容是否正确、准确、真实', NULL, '您是一位专业的数据标注员，负责评估模型输出的正确性。您的任务是根据以下评分标准给出评分：\n<评分标准>\n  正确的答案应当：\n  - 提供准确且完整的信息\n  - 不包含事实性错误\n  - 回答问题的所有部分\n  - 逻辑上保持一致\n  - 使用精确和准确的术语\n\n  在打分时，您应该进行扣分的情况包括：\n  - 事实性错误或不准确的信息\n  - 不完整或部分的答案\n  - 具有误导性或模糊不清的陈述\n  - 错误的术语使用\n  - 逻辑不一致\n  - 缺失关键信息\n</评分标准>\n\n<指导说明>\n  - 仔细阅读输入的问题和模型的输出。\n  - 将输出与参考输出进行对比，以检查事实的准确性和完整性。\n  - 重点关注输出中所呈现信息的正确性，而非其风格或冗长程度。\n</指导说明>\n\n<提醒>\n  目标是评估回复的事实正确性和完整性。\n</提醒>\n\n<输入>\n{{input}}\n</输入>\n\n<输出>\n{{output}}\n</输出>\n\n<参考输出>\n{{reference_output}}\n</参考输出>', 'completed', '{\"columns\":[{\"id\":\"mknyouj31m060qn09us\",\"name\":\"input\",\"description\":\"作为输入投递给评测对象\",\"dataType\":\"String\",\"required\":true},{\"id\":\"mknyouj3sjssa90a5uo\",\"name\":\"reference_output\",\"description\":\"预期理想输出，可作为评估时的参考标准\",\"dataType\":\"String\",\"required\":true}],\"dataSource\":[{\"id\":\"mkosu9w5irflh4356kl\",\"input\":\"帮我规划上海三日游，这周末出发。\",\"reference_output\":\"正确输出地点为上海的三日游规划，包括景点攻略\"}]}', '{\"modelId\":\"1897481367743143938\",\"modelInfo\":{\"provider\":\"DEEPSEEK\",\"modelType\":\"LLM\",\"modelName\":\"deepseek-chat\"}}', 'admin', '2026-01-21 19:23:12', 'admin', '2026-01-22 10:07:51', 'A05A01', NULL, NULL);
INSERT INTO `airag_ext_data` (`id`, `biz_type`, `name`, `descr`, `tags`, `data_value`, `status`, `dataset_value`, `metadata`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `version`) VALUES ('2014158034904305665', 'track', NULL, NULL, NULL, '{\"id\":\"mkosu9w5irflh4356kl\",\"input\":\"帮我规划上海三日游，这周末出发。\",\"reference_output\":\"正确输出地点为上海的三日游规划，包括景点攻略\",\"userQuery\":\"帮我规划上海三日游，这周末出发。\",\"promptAnswer\":\"### 上海三日游行程规划（周末出发）  \\n**出发时间**：本周末（假设周五晚或周六早上抵达上海）  \\n**预算范围**：中等预算（人均约1500-2000元，不含往返大交通）  \\n**主题推荐**：经典地标+文化体验+美食探索  \\n\\n---\\n\\n### **行程总览**\\n| 日期       | 上午活动                 | 下午活动                 | 晚上活动                 | 住宿推荐             |\\n|------------|--------------------------|--------------------------|--------------------------|----------------------|\\n| **第一天** | 外滩+南京路步行街       | 豫园+城隍庙              | 黄浦江夜游               | 南京东路附近经济型酒店 |\\n| **第二天** | 上海博物馆              | 新天地+田子坊            | 上海中心大厦观光         | 同第一天住宿         |\\n| **第三天** | 迪士尼小镇（或武康路）  | 陆家嘴金融区+东方明珠    | 返程                     | —                    |\\n\\n---\\n\\n### **详细行程安排**\\n#### **第一天：经典地标与老城风情**\\n- **上午（9:00-12:00）**  \\n  - **外滩**：欣赏万国建筑群，眺望陆家嘴天际线（免费）。  \\n  - **南京路步行街**：步行至南京路，体验商业街氛围，推荐老字号“沈大成”品尝糕点。  \\n- **中午（12:00-13:30）**  \\n  - **午餐**：南京路附近的“老正兴菜馆”（本帮菜，人均80-120元）。  \\n- **下午（14:00-17:00）**  \\n  - **豫园**：游览明代园林（门票40元），感受江南园林艺术。  \\n  - **城隍庙**：逛传统集市，品尝南翔小笼包（人均30元）。  \\n- **晚上（18:30-20:30）**  \\n  - **黄浦江夜游**：从十六铺码头乘船游览（门票120元/人），欣赏两岸夜景。  \\n- **交通**：全天以地铁为主（推荐购买“上海公共交通卡”或使用支付宝乘车码）。  \\n\\n#### **第二天：文化与现代融合**\\n- **上午（9:30-12:30）**  \\n  - **上海博物馆**（免费，需提前预约）：参观青铜器、书画等藏品（人民广场站）。  \\n- **中午（12:30-14:00）**  \\n  - **午餐**：博物馆附近“大壶春”生煎（人均30元）。  \\n- **下午（14:30-17:30）**  \\n  - **新天地**：石库门建筑改造的时尚街区，适合拍照。  \\n  - **田子坊**：文艺小巷，逛创意小店、咖啡馆。  \\n- **晚上（18:30-21:00）**  \\n  - **上海中心大厦观光厅**（门票180元）：登中国第一高楼俯瞰夜景。  \\n- **交通**：地铁1号线、10号线覆盖主要景点。  \\n\\n#### **第三天：自然与都市风光**\\n- **选项A（适合亲子/乐园爱好者）**  \\n  - **上午**：迪士尼小镇（免费进入，可购物拍照，地铁11号线直达）。  \\n  - **下午**：陆家嘴环形天桥+东方明珠外观拍照。  \\n- **选项B（适合文艺爱好者）**  \\n  - **上午**：武康路历史街区，打卡武康大楼，逛特色咖啡馆。  \\n  - **下午**：陆家嘴参观上海海洋水族馆（门票160元）或环球金融中心观光厅。  \\n- **晚上**：根据返程时间安排，推荐陆家嘴“正大广场”用餐后返程。  \\n\\n---\\n\\n### **预算分配参考（人均）**\\n| 项目       | 费用估算          |\\n|------------|-------------------|\\n| 住宿       | 600元（两晚经济型酒店） |\\n| 餐饮       | 400元             |\\n| 门票       | 400元             |\\n| 市内交通   | 100元             |\\n| 其他       | 100元             |\\n\\n---\\n\\n### **注意事项**\\n1. **预约提醒**：上海博物馆、热门餐厅建议提前1-2天预约。  \\n2. **天气准备**：本周末上海多云，气温18-25℃，建议携带薄外套和雨具。  \\n3. **交通提示**：地铁运营至23:00左右，夜间可打车（推荐使用滴滴）。  \\n\\n如果需要更详细的餐厅推荐、小众景点或调整行程节奏，请随时告诉我！ 🌆\",\"answerScore\":\"得分：0.8\\n原因：模型输出提供了上海三日游的详细规划，包含了行程总览、详细安排、预算和注意事项，信息准确且逻辑一致。然而，参考输出仅要求“正确输出地点为上海的三日游规划，包括景点攻略”，模型输出虽然满足要求，但可能过于详细，且部分内容（如预算、天气）超出了“景点攻略”的严格范围，但未出现事实错误或不准确信息。因此，应该给出的分数是0.8。\"}', 'completed', NULL, '2013935404041412609', NULL, '2026-01-22 10:07:51', NULL, '2026-01-22 10:07:51', NULL, NULL, 1);
INSERT INTO `airag_ext_data` (`id`, `biz_type`, `name`, `descr`, `tags`, `data_value`, `status`, `dataset_value`, `metadata`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `version`) VALUES ('2014165148687159297', 'track', NULL, NULL, NULL, '{\"id\":\"mkou9jjw7esctgvxkjb\",\"input\":\"客户提出新的需求包括考勤统计优化、聊天添加语音功能、聊天记录，展示已读未读消息等\",\"reference_output\":\"整理客户需求，要求简洁\",\"userQuery\":\"客户提出新的需求包括考勤统计优化、聊天添加语音功能、聊天记录，展示已读未读消息等\",\"promptAnswer\":\"```json\\n{\\n  \\\"项目背景\\\": \\\"客户公司计划对现有系统进行功能升级，主要涉及考勤管理和即时通讯两个核心模块的优化与增强。\\\",\\n  \\\"核心痛点\\\": [\\n    \\\"现有考勤统计功能可能效率低下或数据展示不够直观，无法满足精细化管理需求。\\\",\\n    \\\"即时通讯功能单一，缺乏语音消息、聊天记录管理以及消息状态（已读/未读）追踪等现代通讯应用的基础能力。\\\"\\n  ],\\n  \\\"期望目标\\\": [\\n    \\\"优化考勤统计功能，提升数据处理效率与报表展示的清晰度、实用性。\\\",\\n    \\\"为即时通讯模块增加发送/接收语音消息的功能。\\\",\\n    \\\"实现聊天记录的本地或云端存储与便捷检索。\\\",\\n    \\\"在聊天界面中清晰展示消息的已读或未读状态。\\\"\\n  ],\\n  \\\"关键干系人\\\": [\\n    \\\"人力资源部门（考勤统计功能的主要使用者）\\\",\\n    \\\"全体需要使用即时通讯功能的员工\\\",\\n    \\\"系统管理员（负责功能配置与维护）\\\",\\n    \\\"项目决策与管理人员\\\"\\n  ],\\n  \\\"follow_up_questions\\\": [\\n    \\\"考勤统计优化具体指哪些方面？例如，是希望生成更丰富的报表（如迟到早退分析、加班统计）、提升统计速度，还是与请假、出差等流程做更深度整合？\\\",\\n    \\\"对于语音功能，需要明确技术细节：是否支持实时对讲？语音消息是否有时长限制？是否需要支持播放进度控制、语音转文字等附加功能？\\\",\\n    \\\"聊天记录是希望永久保存，还是可设置自动清理周期？存储方案是倾向于本地设备存储，还是公司统一的云端存储？是否需要支持跨设备同步？\\\",\\n    \\\"消息的“已读未读”状态，是否需要更细化的功能，如“已读回执”、“对方正在输入...”提示，或针对群聊的“部分成员已读”状态显示？\\\",\\n    \\\"这些新功能是否有明确的优先级或期望的上线时间表？是否有相关的预算范围或技术平台限制（如必须兼容特定移动端或浏览器）？\\\"\\n  ]\\n}\\n```\",\"answerScore\":\"得分：0.0\\n原因：输出完全不符合简洁性要求。它包含了大量未被请求的背景信息（如“项目背景”、“核心痛点”、“期望目标”、“关键干系人”）、解释性内容以及跟进问题（“follow_up_questions”）。回答没有直接提供被请求的确切信息，而是进行了扩展分析和提问，使用了大量不必要的词汇和结构。因此，应该给出的分数是0.0。\"}', 'completed', NULL, '2013934773104844801', NULL, '2026-01-22 10:36:07', NULL, '2026-01-22 10:36:07', NULL, NULL, 1);
INSERT INTO `airag_ext_data` (`id`, `biz_type`, `name`, `descr`, `tags`, `data_value`, `status`, `dataset_value`, `metadata`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `version`) VALUES ('2014173681512108034', 'track', NULL, NULL, NULL, '{\"id\":\"mkoumpl32mh827mg5b4\",\"input\":\"低代码与零代码的区别，并列举相关优秀的产品\",\"reference_output\":\"Jeecgboot是低代码产品中最流行的产品之一\",\"userQuery\":\"低代码与零代码的区别，并列举相关优秀的产品\",\"promptAnswer\":\"低代码和零代码平台都旨在降低软件开发的门槛，但它们面向的用户群体和技术实现方式有所不同。\\n\\n**低代码平台** 主要面向有一定技术背景的专业开发者或业务技术人员。它通过提供可视化的拖拽组件和模型驱动的逻辑来构建应用，但**仍然允许开发者直接编写代码**来处理复杂的业务逻辑、集成或自定义功能。这种方式在提升开发速度的同时，保留了高度的灵活性和扩展性。例如，开发者可以为一个电商应用快速搭建出用户界面和订单流程，再通过编写代码来实现一个独特的推荐算法或与某个特定老旧系统的深度集成。\\n\\n![低代码平台开发界面](https://images.unsplash.com/photo-1555066931-4365d14bab8c?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80)\\n\\n**零代码平台** 则完全面向**业务人员或完全没有编程经验的用户**。它的目标是让用户通过纯粹的图形化配置，如表单设计、流程编排和规则设定，就能构建出满足特定需求的应用，**整个过程无需编写任何代码**。这极大地加速了简单业务流程的数字化，例如，人力资源部门的同事可以自己搭建一个请假审批流程或一个活动报名系统。\\n\\n![零代码平台操作示意](https://images.unsplash.com/photo-1551288049-bebda4e38f71?ixlib=rb-4.0.3&auto=format&fit=crop&w-800&q=80)\\n\\n**核心区别总结**：\\n1.  **目标用户**：低代码主要服务于“平民开发者”或专业开发者；零代码则服务于纯粹的业务人员。\\n2.  **技术要求**：低代码需要基本的编程思维或技能；零代码几乎无技术门槛。\\n3.  **灵活性**：低代码可通过编码实现高度定制；零代码的能力受限于平台预置的功能模块。\\n4.  **应用场景**：低代码适用于复杂的企业级应用；零代码更擅长解决部门级的、流程固定的轻量级应用。\\n\\n**相关优秀产品列举**：\\n*   **低代码平台代表**：\\n    *   **Mendix**：企业级低代码平台的领导者，功能全面，支持高度复杂的应用开发。\\n    *   **OutSystems**：另一家头部厂商，以高性能、高集成能力和快速开发著称。\\n    *   **微软 Power Apps**：背靠微软生态，与Office 365、Dynamics 365等产品无缝集成，易用性强。\\n*   **零代码平台代表**：\\n    *   **Airtable**：以智能表格为基础，融合了数据库的强大功能和表格的易用性，适合管理多种业务数据。\\n    *   **钉钉宜搭 / 飞书多维表格**：国内协同办公平台内置的零代码工具，与办公场景深度结合，上手极快。\\n    *   **简道云**：国内知名的零代码应用搭建平台，在数据收集、流程管理和报表展示方面表现突出。\\n\\n![企业级软件平台对比](https://images.unsplash.com/photo-1460925895917-afdab827c52f?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80)\",\"answerScore\":\"得分：0.0\\n原因：模型输出中完全没有引用参考文本中提供的引语“Jeecgboot是低代码产品中最流行的产品之一”。模型列举了其他低代码产品，但未提及参考文本中的特定内容，因此未能准确引用文本中实际存在的引语。因此，应该给出的分数是0.0。\"}', 'completed', NULL, '2013925759721709570', NULL, '2026-01-22 11:10:02', NULL, '2026-01-22 11:10:01', NULL, NULL, 1);


