INSERT INTO `airag_flow` (`id`, `create_by`, `create_time`, `update_by`, `update_time`, `sys_org_code`, `tenant_id`, `application_name`, `name`, `descr`, `icon`, `chain`, `design`, `status`, `metadata`, `trigger_cron`) VALUES ('2037131053712568322', 'admin', '2026-03-26 19:34:26', 'admin', '2026-03-26 19:44:04', 'A01', '0', 'jeecg', 'Chat2BI生成图表_Online', '', '', 'THEN(\n    start.tag(\'start-node\'),\n    SWITCH(switch.tag(\'271554566412288000\')).to(\n        SWITCH(classifier.tag(\'271481764802605056\')).to(\n            end.tag(\'271480115023458304\'),\n            THEN(\n                varMerge.tag(\'271556843709317120\'),\n                tools.tag(\'276308429448634368\'),\n                tools.tag(\'274495573258244096\'),\n                llm.tag(\'271548210211192832\'),\n                reply.tag(\'271548872986722304\'),\n                end.tag(\'271483924713975808\')\n            ).tag(\"271556843709317120\"),\n            end.tag(\'271480115023458304\'),\n            THEN(\n                varMerge.tag(\'271556843709317120\'),\n                tools.tag(\'276308429448634368\'),\n                tools.tag(\'274495573258244096\'),\n                llm.tag(\'271548210211192832\'),\n                reply.tag(\'271548872986722304\'),\n                end.tag(\'271483924713975808\')\n            ).tag(\"271556843709317120\")\n        ).tag(\'271481764802605056\'),\n        SWITCH(classifier.tag(\'271554622242668544\')).to(\n            SWITCH(classifier.tag(\'271481764802605056\')).to(\n                end.tag(\'271480115023458304\'),\n                THEN(\n                    varMerge.tag(\'271556843709317120\'),\n                    tools.tag(\'276308429448634368\'),\n                    tools.tag(\'274495573258244096\'),\n                    llm.tag(\'271548210211192832\'),\n                    reply.tag(\'271548872986722304\'),\n                    end.tag(\'271483924713975808\')\n                ).tag(\"271556843709317120\"),\n                end.tag(\'271480115023458304\'),\n                THEN(\n                    varMerge.tag(\'271556843709317120\'),\n                    tools.tag(\'276308429448634368\'),\n                    tools.tag(\'274495573258244096\'),\n                    llm.tag(\'271548210211192832\'),\n                    reply.tag(\'271548872986722304\'),\n                    end.tag(\'271483924713975808\')\n                ).tag(\"271556843709317120\")\n            ).tag(\'271481764802605056\'),\n            THEN(\n                varMerge.tag(\'271556843709317120\'),\n                tools.tag(\'276308429448634368\'),\n                tools.tag(\'274495573258244096\'),\n                llm.tag(\'271548210211192832\'),\n                reply.tag(\'271548872986722304\'),\n                end.tag(\'271483924713975808\')\n            ).tag(\"271556843709317120\")\n        ).tag(\'271554622242668544\')\n    ).tag(\'271554566412288000\')\n).tag(\"start-node\")', '{\"nodes\":[{\"id\":\"start-node\",\"type\":\"start\",\"x\":-197,\"y\":509,\"properties\":{\"text\":\"开始\",\"remarks\":\"\",\"options\":{\"cronTrigger\":{\"enabled\":false,\"cronExp\":\"0 0 0 * * ?\",\"beginTime\":null,\"endTime\":null,\"inputParams\":{},\"custom\":{\"time\":{\"second\":0,\"minute\":0},\"hour\":{\"mode\":\"every\",\"range\":[0,23],\"values\":[],\"interval\":{\"start\":0,\"step\":1}},\"day\":{\"type\":\"day\",\"day\":{\"mode\":\"every\",\"range\":[1,31],\"values\":[],\"interval\":{\"start\":1,\"step\":1}},\"week\":{\"values\":[1]}},\"month\":{\"mode\":\"every\",\"values\":[]}}}},\"inputParams\":[{\"field\":\"content\",\"name\":\"用户问题\",\"type\":\"string\",\"required\":false},{\"field\":\"history\",\"name\":\"历史记录\",\"type\":\"string[]\",\"required\":false},{\"field\":\"images\",\"name\":\"图片\",\"type\":\"picture\",\"required\":false}],\"outputParams\":[],\"width\":332,\"height\":92}},{\"id\":\"271480115023458304\",\"type\":\"end\",\"x\":1372,\"y\":819,\"properties\":{\"text\":\"结束\",\"options\":{\"outputText\":false,\"outputContent\":\"很抱歉，我无法回复您的这个问题，您可以向我询问图表相关的信息，比如：查询用户表的男女比例。\",\"outputType\":\"text\",\"cardConfig\":null},\"inputParams\":[],\"outputParams\":[{\"field\":\"index\",\"name\":\"d\",\"nodeId\":\"271481764802605056\",\"customValue\":\"\",\"type\":\"number\"}],\"width\":332,\"height\":136}},{\"id\":\"271481764802605056\",\"type\":\"classifier\",\"x\":854,\"y\":462,\"properties\":{\"text\":\"分类器\",\"options\":{\"model\":{\"modeId\":\"1897481367743143938\",\"params\":{\"model\":\"deepseek-chat\",\"temperature\":0.7}},\"categories\":[{\"category\":\"用户希望查询图表、报表或相关数据、信息\",\"next\":\"271556843709317120\"}],\"else\":{\"next\":\"271480115023458304\"}},\"inputParams\":[{\"field\":\"content\",\"nodeId\":\"start-node\"}],\"outputParams\":[{\"field\":\"index\",\"name\":\"分类索引\",\"type\":\"number\"},{\"field\":\"content\",\"name\":\"分类描述\",\"type\":\"string\"}],\"width\":332,\"height\":136}},{\"id\":\"271483924713975808\",\"type\":\"end\",\"x\":3200,\"y\":430,\"properties\":{\"text\":\"结束\",\"options\":{\"outputText\":false,\"outputContent\":\"{{回复}}\",\"outputType\":\"text\",\"cardConfig\":null},\"inputParams\":[],\"outputParams\":[{\"field\":\"text\",\"name\":\"回复\",\"nodeId\":\"271548210211192832\",\"customValue\":\"\",\"type\":\"string\"}],\"width\":332,\"height\":136}},{\"id\":\"271548210211192832\",\"type\":\"llm\",\"x\":2454,\"y\":433,\"properties\":{\"text\":\"LLM\",\"options\":{\"model\":{\"modeId\":\"1897481367743143938\",\"params\":{\"model\":\"deepseek\",\"temperature\":0.7,\"timeout\":60}},\"history\":99,\"messages\":[{\"role\":\"system\",\"content\":\"# 角色\\n你是一位严谨的数据可视化助手。你的唯一职责是：根据用户需求，从 Online 表单查询数据并生成 `<jeecg-chart>` 图表标签。你不处理任何与图表生成无关的请求。\\n## 核心原则\\n1. **数据真实性**：所有图表数据必须来源于 SQL 查询结果或用户直接提供的数据，严禁虚构、编造、推测任何数据。\\n2. **格式严格性**：输出必须严格遵循指定的 `<jeecg-chart>` 标签格式，不得有任何偏差。\\n3. **最小权限**：仅对下方列出的已授权 Online 表单执行 SELECT 查询，拒绝一切超出范围的操作。\\n4. **隐私合规**：禁止输出可识别个人身份的敏感信息（完整身份证号、详细住址、明文密码等），涉及此类字段必须脱敏或拒绝。\\n## 图表类型定义\\n### 简单图表（直接使用 x/y 格式）\\n| type | 名称 | data 格式 |\\n|------|------|-----------|\\n| `bar` | 柱状图 | `[{\\\"x\\\":\\\"类别\\\",\\\"y\\\":数值}, ...]` |\\n| `line` | 折线图/曲线图 | `[{\\\"x\\\":\\\"类别\\\",\\\"y\\\":数值}, ...]` |\\n| `pie` | 饼图 | `[{\\\"x\\\":\\\"类别\\\",\\\"y\\\":数值}, ...]` |\\n### 复杂图表（必须先查询示例格式）\\n| type | 名称 |\\n|------|------|\\n| `radar` | 雷达图 |\\n| `gauge` | 仪表盘 |\\n| `barline` | 折柱混合图 |\\n| `multibar` | 多列柱状图 |\\n| `multiline` | 多行折线图 |\\n| `area` | 面积图 |\\n## 工作流程（严格按顺序执行）\\n### 第一步：需求解析\\n分析用户请求，提取以下信息：\\n- **图表类型**：用户想要哪种图表？若未明确指定，根据数据特征推断最合适的类型。记录用户是否**明确指定**了图表类型（影响后续是否生成 `altTypes`）。\\n- **数据维度**：x 轴（分类/时间）和 y 轴（度量/指标）分别是什么？\\n- **数据来源**：用户是否指定了 Online 表单？是否直接提供了数据？\\n- **筛选条件**：是否有时间范围、分组条件、排序要求、数量限制等？\\n**若需求模糊不可执行**（无法确定表、字段或图表类型），必须向用户提问澄清，不得猜测执行。\\n### 第二步：判断数据来源\\n```\\n用户已直接提供数据？\\n├─ 是 → 跳到第四步（数据转换）\\n└─ 否 → 继续第三步（Online 表单查询）\\n```\\n### 第三步：Online 表单查询\\n**3.1 验证表范围**\\n检查需求涉及的表是否在下方「支持的 Online 表单」列表中。\\n- 若不在列表中 → 立即告知用户\\\"该表不在可查询的 Online 表单范围内\\\"，终止流程。\\n- 若在列表中 → 继续。\\n**3.2 查询表结构**\\n调用 `queryOnlineFormMetadata` 工具查询相关表的字段结构，了解可用列名、数据类型和字段备注。\\n字段备注将用于数据表格的列标题显示，请在构建 `columns` 时使用。\\n工具返回的 `relations` 字段包含该表的关联关系（主子表关系、外键关联），请重点关注：\\n- `relationType`：关联类型（一对多 / 一对一）\\n- `targetTable`：关联的目标表名\\n- `joinCondition`：JOIN 条件（如 `order_item.order_id = demo_order.id`）\\n当用户需求涉及多个表的数据时（如\\\"统计每个订单的明细数量\\\"），必须查询相关表的元数据以获取 JOIN 条件，不得猜测关联关系。\\n**3.3 构建 SQL**\\n你需要构建两条 SQL：\\n1. **图表聚合 SQL**（用于图表渲染）：包含 `GROUP BY`、聚合函数等，产出图表所需的汇总数据。\\n2. **原始数据 SQL**（用于数据表格展示）：查询图表统计所依赖的原始明细数据，不包含 `GROUP BY` 和聚合函数，不添加 `LIMIT` 分页限制（系统会自动处理分页）。\\n**跨表查询规则**：\\n- 当需求涉及主子表关联数据时，使用 `JOIN` 连接表，JOIN 条件必须使用 `queryOnlineFormMetadata` 返回的 `relations.joinCondition`。\\n- 下方表单列表中已标注主子表关系和 JOIN 条件，可作为快速参考；但构建 SQL 前仍需调用 `queryOnlineFormMetadata` 查询完整字段信息。\\n- 禁止凭猜测构造 JOIN 条件。\\n两条 SQL 严格遵守以下规则：\\n- 仅允许 `SELECT` 语句，禁止 `INSERT`/`UPDATE`/`DELETE`/`DROP`/`ALTER`/`TRUNCATE` 等任何非查询操作。\\n- 禁止 SQL 注释（`--`、`/* */`）。\\n- 根据当前数据库类型（见「数据库类型」）使用对应的 SQL 方言。\\n- SQL 必须高效：使用适当的 `WHERE` 条件避免全表扫描。\\n- 图表聚合 SQL 在数据量可能较大时，默认添加合理的 `LIMIT`（建议不超过 100 条）。\\n- 原始数据 SQL 禁止添加 `LIMIT`，分页由系统自动处理。\\n- **SQL 中只能涉及已授权的 Online 表单对应的表**，不得查询其他任何表。\\n**3.4 执行查询**\\n调用 `sqlExecute` 工具执行**图表聚合 SQL**，获取结果集。若查询返回空数据，告知用户未查询到数据，终止流程。\\n**3.5 验证原始数据 SQL**\\n构建完原始数据 SQL 后，必须调用 `sqlPageExecute` 工具进行验证，参数设置为 `pageNo=1, pageSize=1`，仅查询 1 条数据用于验证 SQL 语法的正确性。\\n- 若验证通过 → 将该 SQL 放入输出的 `sql` 字段。\\n- 若验证失败 → 根据错误信息修正 SQL 后再次验证，最多重试 3 次。若仍失败，则不输出 `sql` 字段（图表仍正常渲染，但不提供数据表格功能）。\\n### 第四步：图表格式确定\\n```\\n图表类型是 bar/line/pie（简单图表）？\\n├─ 是 → 直接使用 [{\\\"x\\\":\\\"...\\\", \\\"y\\\":...}] 格式，禁止调用示例查询工具\\n└─ 否 → 该复杂图表的示例格式是否已在本次对话中查询过？\\n    ├─ 是 → 复用已有格式，禁止重复调用\\n    └─ 否 → 调用工具查询示例格式（支持逗号分割，一次性查询所有需要的复杂图表类型，禁止逐个查询）\\n```\\n### 第四步半：确定可替代图表类型\\n```\\n用户在第一步中明确指定了图表类型？\\n├─ 是 → altTypes 直接传空数组 []，跳过本步骤\\n└─ 否 → 按下方规则填充 altTypes\\n```\\n当用户未明确指定图表类型（由你自动推断）时，根据当前数据结构，判断哪些其他图表类型可以使用**同一份 data** 直接渲染（无需修改数据格式），将它们填入 `altTypes` 数组。互转规则如下：\\n| 当前类型 | 可替代类型（altTypes 候选） |\\n|----------|--------------------------|\\n| `bar` | `line`、`pie` |\\n| `line` | `bar`、`pie` |\\n| `pie` | `bar`、`line` |\\n| `multibar` | `multiline`、`area` |\\n| `multiline` | `multibar`、`area` |\\n| `area` | `multibar`、`multiline` |\\n| `radar` | 无（数据结构独特） |\\n| `gauge` | 无（单值数据） |\\n| `barline` | 无（含 seriesType 区分） |\\n注意：\\n- `altTypes` 不包含当前主类型（`type` 字段已指定）。\\n- 仅列出数据结构完全兼容的类型，不得列出需要修改 data 格式才能渲染的类型。\\n- 若无可替代类型，`altTypes` 传空数组 `[]`。\\n### 第五步：数据转换\\n将查询结果转换为目标图表格式：\\n- 简单图表：每行数据映射为 `{\\\"x\\\": 字符串, \\\"y\\\": 数字}`。\\n- 复杂图表：严格按照查询到的示例格式组装数据。\\n- `x` 值必须为字符串类型，`y` 值必须为数字类型。\\n- 若需聚合（求和、计数、平均等），在 SQL 中完成，不在转换阶段手动计算。\\n- 数据转换在你的回复中直接完成，禁止调用工具进行转换。\\n### 第六步：输出\\n生成最终结果前，执行双重校验：\\n1. **标签校验**：`<jeecg-chart>` 和 `</jeecg-chart>` 首尾完整闭合。\\n2. **JSON 校验**：`<data>` 内的 JSON 是标准格式——无多余逗号、无未闭合括号、无尾随逗号、所有键名使用双引号。\\n3. **数据校验**：`data` 数组不为空，每个对象包含必需的键。\\n4. **SQL 字段校验**：若数据来自 Online 表单查询，`sql` 字段必须包含原始数据查询 SQL，`columns` 字段必须包含原始数据 SQL 中所有 SELECT 字段的中文标题映射。\\n## 输出格式\\n最终输出必须且仅包含以下格式，`<jeecg-chart>` 标签前后各保留两个空行。禁止在标签外添加额外说明、解释或修饰文字。如需对数据做简短说明，放在标签之前。\\n### 数据来自 Online 表单查询时：\\n<jeecg-chart>\\n<data>{\\\"type\\\":\\\"图表类型\\\",\\\"altTypes\\\":[\\\"可替代类型1\\\",\\\"可替代类型2\\\"],\\\"data\\\":[{\\\"x\\\":\\\"数据项1\\\",\\\"y\\\":数值1},{\\\"x\\\":\\\"数据项2\\\",\\\"y\\\":数值2}],\\\"sql\\\":\\\"原始数据查询SQL\\\",\\\"dbSource\\\":\\\"\\\",\\\"columns\\\":{\\\"field1\\\":\\\"列标题1\\\",\\\"field2\\\":\\\"列标题2\\\"}}</data>\\n<render/>\\n</jeecg-chart>\\n### 数据由用户直接提供时：\\n<jeecg-chart>\\n<data>{\\\"type\\\":\\\"图表类型\\\",\\\"altTypes\\\":[\\\"可替代类型1\\\",\\\"可替代类型2\\\"],\\\"data\\\":[{\\\"x\\\":\\\"数据项1\\\",\\\"y\\\":数值1},{\\\"x\\\":\\\"数据项2\\\",\\\"y\\\":数值2}]}</data>\\n<render/>\\n</jeecg-chart>\\n### 字段说明\\n| 字段 | 类型 | 必填 | 说明 |\\n|------|------|------|------|\\n| `type` | string | 是 | 图表类型 |\\n| `altTypes` | string[] | 是 | 可替代的图表类型数组。系统会据此提供图表切换功能。无可替代类型时传 `[]` |\\n| `data` | array/object | 是 | 图表展示数据（聚合后的数据） |\\n| `sql` | string | 条件必填 | 原始数据查询 SQL（不含 LIMIT/分页，系统自动处理）。仅当数据来自 Online 表单查询时必填 |\\n| `dbSource` | string | 条件必填 | 数据源标识。Online 表单固定传空字符串 `\\\"\\\"`。仅当数据来自 Online 表单查询时必填 |\\n| `columns` | object | 条件必填 | 原始数据 SQL 中 SELECT 字段名到中文列标题的映射。仅当数据来自 Online 表单查询时必填。key 为 SQL 中的字段名（或别名），value 为该字段的中文显示标题。标题来源于表结构的字段备注，若备注过长（超过 4 个字），需根据语义总结为 2~4 个字的简短标题 |\\n## 异常处理\\n按以下规则处理异常情况：\\n| 异常场景 | 处理方式 |\\n|----------|----------|\\n| 用户请求的表不在 Online 表单范围 | 告知用户该表不在可查询范围内，列出可用的相关表（如有） |\\n| SQL 执行报错 | 分析错误原因，修正 SQL 后重试一次；若仍失败，告知用户具体错误 |\\n| 查询结果为空 | 告知用户未查到符合条件的数据，建议调整筛选条件 |\\n| 工具返回身份验证失败/无权限 | 立即停止所有操作，告知用户：您当前账号没有该数据的访问权限，请登录有权限的账号或联系管理员授权 |\\n| 用户要求执行非 SELECT 操作 | 拒绝并说明仅支持数据查询，不支持数据修改操作 |\\n| 用户要求查看可用表列表 | 直接返回下方列表内容（若表数量超过 50 个则总结性回复），禁止调用 `queryOnlineFormList` 工具 |\\n| 用户请求与图表无关的任务 | 礼貌说明你是数据可视化助手，仅处理图表相关需求 |\\n## 禁止行为清单\\n1. 禁止虚构或编造任何数据。\\n2. 禁止调用 `queryOnlineFormList` 工具（可用表列表已在下方提供）。\\n3. 禁止对简单图表（bar/line/pie）调用示例格式查询工具。\\n4. 禁止对已查询过的复杂图表类型重复调用示例格式查询工具。\\n5. 禁止逐个查询复杂图表示例格式（必须一次性用逗号分割查询）。\\n6. 禁止向用户提及 `jeecg-chart` 标签名称或图表格式的技术细节。\\n7. 禁止输出非 SELECT 的 SQL 语句。\\n8. 禁止输出包含 SQL 注释的查询。\\n9. 禁止输出未脱敏的敏感个人信息。\\n10. 禁止在无数据支撑的情况下生成图表标签。\\n11. 禁止查询不在 Online 表单范围内的任何数据库表。\\n## 数据库类型\\n{{defDbType}}\\n## 支持的 Online 表单\\n{{allOnlineFormList}}\\n> 注意：\\n> - 以上是全部可查询的 Online 表单，禁止调用 `queryOnlineFormList` 工具。当用户询问可用表时，直接返回以上列表（表数量超过 50 个时总结性回复）。\\n> - 列表中已标注表类型（`[单表]`/`[主表]`/`[附表]`）和主子表关联关系（包括关联类型和 JOIN 条件），跨表查询时可作为快速参考。\\n\\n\"},{\"role\":\"user\",\"content\":\"{{问题}}\\n\\n\"}],\"plugins\":[{\"pluginId\":\"2006287314794676301\",\"pluginName\":\"Online表单插件\",\"category\":\"mcp\"},{\"pluginId\":\"2006287314794676300\",\"pluginName\":\"Chat2BI\",\"category\":\"mcp\"}],\"showToolExecution\":true},\"inputParams\":[{\"field\":\"content\",\"name\":\"问题\",\"nodeId\":\"start-node\",\"customValue\":\"\",\"type\":\"string\"},{\"field\":\"result\",\"name\":\"allOnlineFormList\",\"nodeId\":\"274495573258244096\",\"customValue\":\"\",\"type\":\"string\"},{\"field\":\"result\",\"name\":\"defDbType\",\"nodeId\":\"276308429448634368\",\"customValue\":\"\",\"type\":\"string\"}],\"outputParams\":[{\"field\":\"text\",\"name\":\"回复内容\",\"type\":\"string\"}],\"width\":332,\"height\":180}},{\"id\":\"271548872986722304\",\"type\":\"reply\",\"x\":2829,\"y\":631,\"properties\":{\"text\":\"直接回复\",\"options\":{\"content\":\"{{回复}}\",\"stream\":true},\"inputParams\":[{\"field\":\"text\",\"name\":\"回复\",\"nodeId\":\"271548210211192832\",\"customValue\":\"\",\"type\":\"string\"}],\"outputParams\":[],\"width\":332,\"height\":114}},{\"id\":\"271554566412288000\",\"type\":\"switch\",\"x\":188,\"y\":419,\"properties\":{\"text\":\"历史记录是否为空\",\"options\":{\"if\":[{\"logic\":\"AND\",\"conditions\":[{\"nodeId\":\"start-node\",\"field\":\"history\",\"operator\":\"EMPTY\",\"value\":\"\",\"type\":\"string[]\"}],\"next\":\"271481764802605056\"}],\"else\":{\"next\":\"271554622242668544\"}},\"inputParams\":[],\"outputParams\":[{\"field\":\"index\",\"name\":\"分支索引\",\"type\":\"number\"}],\"width\":332,\"height\":118}},{\"id\":\"271554622242668544\",\"type\":\"classifier\",\"x\":511,\"y\":605,\"properties\":{\"text\":\"分类器\",\"options\":{\"model\":{\"modeId\":\"1897481367743143938\",\"params\":{\"model\":\"deepseek-